+async function checkAgenticFlow(): Promise<HealthCheck> {
+  try {
+    // Walk common node_modules paths to find agentic-flow/package.json
+    const candidates = [
+      join(process.cwd(), 'node_modules', 'agentic-flow', 'package.json'),
+      join(process.cwd(), '..', 'node_modules', 'agentic-flow', 'package.json'),
