+      exports['./router'] ? 'Router' : null,
+      exports['./transport/quic'] ? 'QUIC' : null,
+    ].filter(Boolean);
+    return {
+      name: 'agentic-flow',
+      status: 'pass',
+      message: `v${version} (${features.join(', ')})`
+    };
+  } catch {
+    return { name: 'agentic-flow', status: 'warn', message: 'Check failed' };
